from qiskit import QuantumCircuit
from typing import List, Tuple, Dict

class LayerAnalyzer:
    """Analyze circuits layer by layer."""

    def __init__(self, circuit: QuantumCircuit):
        self.circuit = circuit
        self.layers = self._extract_layers()

    def _extract_layers(self) -> List[List[Tuple]]:
        """Extract operations into layers based on dependencies."""
        layers = []
        current_layer = []
        qubits_used = set()

        for instruction, qargs, cargs in self.circuit.data:
            qubit_indices = set(q._index for q in qargs)

            if qubits_used.intersection(qubit_indices):
                if current_layer:
                    layers.append(current_layer)
                current_layer = [(instruction, qargs, cargs)]
                qubits_used = qubit_indices
            else:
                current_layer.append((instruction, qargs, cargs))
                qubits_used.update(qubit_indices)

        if current_layer:
            layers.append(current_layer)

        return layers

    def num_layers(self) -> int:
        return len(self.layers)

    def get_layer_circuit(self, layer_idx: int) -> QuantumCircuit:
        if layer_idx >= len(self.layers):
            raise IndexError(f"Layer {layer_idx} does not exist")

        layer_qc = QuantumCircuit(self.circuit.num_qubits)
        for inst, qargs, cargs in self.layers[layer_idx]:
            qubit_indices = [q._index for q in qargs]
            layer_qc.append(inst, qubit_indices)
        return layer_qc

    def get_circuit_up_to(self, layer_idx: int) -> QuantumCircuit:
        partial = QuantumCircuit(self.circuit.num_qubits)
        for i in range(min(layer_idx + 1, len(self.layers))):
            for inst, qargs, cargs in self.layers[i]:
                qubit_indices = [q._index for q in qargs]
                partial.append(inst, qubit_indices)
        return partial

    def get_layer_stats(self, layer_idx: int) -> Dict:
        if layer_idx >= len(self.layers):
            return {}
        layer = self.layers[layer_idx]
        qubits = set()
        gate_types = {}
        for inst, qargs, cargs in layer:
            qubits.update(q._index for q in qargs)
            gate_types[inst.name] = gate_types.get(inst.name, 0) + 1
        return {
            'num_gates': len(layer),
            'qubits_used': sorted(qubits),
            'gate_types': gate_types
        }

    def print_summary(self):
        print(f"Circuit Analysis: {self.num_layers()} layers")
        print("=" * 50)
        for i in range(self.num_layers()):
            stats = self.get_layer_stats(i)
            gates = ', '.join(f"{g}({c})" for g, c in stats['gate_types'].items())
            print(f"Layer {i}: {gates} on qubits {stats['qubits_used']}")

from qiskit import QuantumCircuit
from qiskit.quantum_info import Statevector
import numpy as np
from typing import List, Dict

class StateEvolutionTracker:
    """Track state evolution through a circuit."""

    def __init__(self, circuit: QuantumCircuit):
        self.circuit = circuit.remove_final_measurements(inplace=False)
        self.evolution = self._compute_evolution()

    def _compute_evolution(self) -> List[Dict]:
        evolution = []
        partial = QuantumCircuit(self.circuit.num_qubits)

        # Initial state
        sv = Statevector.from_instruction(partial)
        evolution.append({
            'step': 0,
            'gate': 'initial',
            'statevector': sv.data.copy(),
            'probabilities': sv.probabilities()
        })

        for i, (inst, qargs, cargs) in enumerate(self.circuit.data):
            qubit_indices = [q._index for q in qargs]
            partial.append(inst, qubit_indices)
            sv = Statevector.from_instruction(partial)
            evolution.append({
                'step': i + 1,
                'gate': inst.name,
                'statevector': sv.data.copy(),
                'probabilities': sv.probabilities()
            })

        return evolution

    def get_state_at_step(self, step: int) -> np.ndarray:
        if step >= len(self.evolution):
            raise IndexError(f"Step {step} does not exist")
        return self.evolution[step]['statevector']

    def get_nonzero_amplitudes(self, step: int, threshold: float = 1e-10) -> Dict:
        sv = self.get_state_at_step(step)
        n = int(np.log2(len(sv)))
        result = {}
        for i, amp in enumerate(sv):
            if abs(amp) > threshold:
                basis = format(i, f'0{n}b')
                result[basis] = {'amplitude': amp, 'probability': abs(amp)**2}
        return result

    def compare_with_expected(self, step: int, expected: np.ndarray) -> Dict:
        actual = self.get_state_at_step(step)
        fidelity = abs(np.vdot(actual, expected))**2
        match = fidelity > 0.9999
        differences = []
        for i, (a, e) in enumerate(zip(actual, expected)):
            if abs(a - e) > 1e-6:
                n = int(np.log2(len(actual)))
                differences.append({
                    'basis': format(i, f'0{n}b'),
                    'actual': a,
                    'expected': e
                })
        return {'match': match, 'fidelity': fidelity, 'differences': differences}

    def print_evolution(self):
        n = self.circuit.num_qubits
        print(f"State Evolution ({n} qubits)")
        print("=" * 60)
        for entry in self.evolution:
            print(f"\nStep {entry['step']}: {entry['gate']}")
            nonzero = self.get_nonzero_amplitudes(entry['step'])
            for basis, data in nonzero.items():
                amp = data['amplitude']
                prob = data['probability']
                print(f"  |{basis}⟩: {amp:.4f} (p={prob:.4f})")

from qiskit import QuantumCircuit
from qiskit.quantum_info import Statevector
import numpy as np
from typing import Dict, List, Optional, Callable

class CheckpointDebugger:
    """Interactive checkpoint-based debugger."""

    def __init__(self, circuit: QuantumCircuit):
        self.circuit = circuit.remove_final_measurements(inplace=False)
        self.checkpoints: Dict[str, int] = {}
        self.breakpoint_conditions: Dict[str, Callable] = {}

    def add_checkpoint(self, name: str, after_gate: int):
        self.checkpoints[name] = after_gate

    def add_conditional_breakpoint(self, name: str, after_gate: int,
                                   condition: Callable[[np.ndarray], bool]):
        self.checkpoints[name] = after_gate
        self.breakpoint_conditions[name] = condition

    def _build_circuit_to(self, gate_idx: int) -> QuantumCircuit:
        partial = QuantumCircuit(self.circuit.num_qubits)
        for i, (inst, qargs, cargs) in enumerate(self.circuit.data):
            if i >= gate_idx:
                break
            qubit_indices = [q._index for q in qargs]
            partial.append(inst, qubit_indices)
        return partial

    def get_state(self, checkpoint: str) -> Dict:
        if checkpoint not in self.checkpoints:
            raise ValueError(f"Checkpoint '{checkpoint}' not found")

        gate_idx = self.checkpoints[checkpoint]
        partial = self._build_circuit_to(gate_idx)
        sv = Statevector.from_instruction(partial)

        n = self.circuit.num_qubits
        amplitudes = {}
        for i, amp in enumerate(sv.data):
            if abs(amp) > 1e-10:
                amplitudes[format(i, f'0{n}b')] = amp

        return {
            'checkpoint': checkpoint,
            'gate_index': gate_idx,
            'statevector': sv.data,
            'amplitudes': amplitudes,
            'probabilities': dict(sv.probabilities_dict())
        }

    def diff_checkpoints(self, cp1: str, cp2: str) -> Dict:
        state1 = self.get_state(cp1)
        state2 = self.get_state(cp2)

        sv1, sv2 = state1['statevector'], state2['statevector']
        fidelity = abs(np.vdot(sv1, sv2))**2

        prob_diff = {}
        all_keys = set(state1['probabilities']) | set(state2['probabilities'])
        for k in all_keys:
            p1 = state1['probabilities'].get(k, 0)
            p2 = state2['probabilities'].get(k, 0)
            if abs(p2 - p1) > 1e-10:
                prob_diff[k] = {'before': p1, 'after': p2, 'change': p2 - p1}

        return {
            'from': cp1,
            'to': cp2,
            'fidelity': fidelity,
            'probability_changes': prob_diff
        }

    def check_breakpoints(self) -> List[str]:
        triggered = []
        for name, condition in self.breakpoint_conditions.items():
            state = self.get_state(name)
            if condition(state['statevector']):
                triggered.append(name)
        return triggered

    def run_to_checkpoint(self, name: str) -> Dict:
        return self.get_state(name)
